#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <errno.h>

/*
 * Process Management in C using fork() and exec()
 * Demonstrates:
 * 1. Creating child processes with fork()
 * 2. Process identification (PID, PPID)
 * 3. Executing new programs with exec()
 * 4. Parent waiting for child with wait()
 */

void print_process_info(const char *process_name) {
 printf("[%s] PID: %d, PPID: %d\n", 
 process_name, getpid(), getppid());
}

void demonstrate_fork() {
 printf("\n=== Fork Demonstration ===\n");

 pid_t pid = fork();

 if (pid < 0) {
 // Fork failed
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 else if (pid == 0) {
 // Child process
 print_process_info("CHILD");
 printf("Child: fork() returned 0\n");
 printf("Child: Executing new program...\n");

 // Replace child with 'ls' command
 char *args[] = {"ls", "-l", NULL};
 execvp("ls", args);

 // If execvp returns, it failed
 perror("execvp failed");
 exit(EXIT_FAILURE);
 }
 else {
 // Parent process
 print_process_info("PARENT");
 printf("Parent: fork() returned child PID: %d\n", pid);
 printf("Parent: Waiting for child to complete...\n");

 int status;
 waitpid(pid, &status, 0); // Wait for child

 if (WIFEXITED(status)) {
 printf("Parent: Child exited with status: %d\n", 
 WEXITSTATUS(status));
 }
 }
}

void demonstrate_multiple_children() {
 printf("\n=== Multiple Children Demonstration ===\n");

 pid_t children[3];

 for (int i = 0; i < 3; i++) {
 pid_t pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(EXIT_FAILURE);
 }
 else if (pid == 0) {
 // Child process
 printf("Child %d (PID: %d): Starting task...\n", i+1, getpid());
 sleep(1); // Simulate work
 printf("Child %d (PID: %d): Task completed!\n", i+1, getpid());
 exit(i + 1); // Exit with unique status
 }
 else {
 children[i] = pid;
 printf("Parent: Created child %d with PID: %d\n", i+1, pid);
 }
 }

 // Parent waits for all children
 printf("Parent: Waiting for all children...\n");
 for (int i = 0; i < 3; i++) {
 int status;
 pid_t terminated_pid = waitpid(children[i], &status, 0);
 if (WIFEXITED(status)) {
 printf("Parent: Child %d (PID: %d) exited with status: %d\n",
 i+1, terminated_pid, WEXITSTATUS(status));
 }
 }
}

void demonstrate_zombie_orphan() {
 printf("\n=== Zombie Process Demonstration ===\n");

 pid_t pid = fork();

 if (pid == 0) {
 // Child process - exits immediately becoming zombie
 printf("Child: I am about to exit and become a zombie\n");
 exit(0);
 }
 else {
 // Parent process - sleeps before calling wait()
 printf("Parent: Child PID: %d\n", pid);
 printf("Parent: Sleeping for 2 seconds (child becomes zombie)...\n");
 sleep(2);

 int status;
 waitpid(pid, &status, 0);
 printf("Parent: Called wait(), zombie is now cleaned up\n");
 }
}

int main() {
 printf("Process Management Demo in C\n");
 printf("Main Process PID: %d\n", getpid());

 // Demonstrate fork() and exec()
 demonstrate_fork();

 // Demonstrate multiple child processes
 demonstrate_multiple_children();

 // Demonstrate zombie process
 demonstrate_zombie_orphan();

 printf("\nAll demonstrations complete!\n");
 return 0;
}
